import { test, expect } from '@playwright/test';

test.use({ storageState: 'studio/.auth/successfactors.json' });

test('Amazon.sg: Search and read product title and price for Magic Tree House Boxed Set', async ({ page }) => {
  await test.step('Launch browser and navigate to Amazon Singapore', async () => {
    await page.goto('about:blank');
    await page.goto('https://www.amazon.sg');
  });

  await test.step('Wait for search box and submit search', async () => {
    await page.waitForSelector('input[name="field-keywords"]');
    await page.fill('input[name="field-keywords"]', 'Magic Tree House Boxed Set');
    await page.press('input[name="field-keywords"]', 'Enter');
  });

  await test.step('Wait for search results and click first product', async () => {
    await page.waitForSelector('.s-search-results .s-result-item h2 a');
    await page.click('.s-search-results .s-result-item h2 a');
    await page.waitForTimeout(1500);
  });

  let productTitle = '';
  let productPriceText = '';
  let productPriceNumber: number | null = null;

  await test.step('Wait for product detail page and read product title', async () => {
    await page.waitForSelector('#productTitle');
    productTitle = (await page.textContent('#productTitle'))?.trim() || '';
    expect(productTitle.length).toBeGreaterThan(0);
  });

  await test.step('Read the product price element and parse as number', async () => {
    // Try all possible selectors in order as per the exploration doc
    let priceElement = null;
    if (await page.locator('#priceblock_ourprice').count()) {
      priceElement = '#priceblock_ourprice';
    } else if (await page.locator('#priceblock_dealprice').count()) {
      priceElement = '#priceblock_dealprice';
    } else if (await page.locator('.a-price .a-offscreen').count()) {
      priceElement = '.a-price .a-offscreen';
    }

    expect(priceElement).not.toBeNull();

    productPriceText = (await page.textContent(priceElement!))?.trim() || '';
    // Remove currency symbols and commas, parse as float
    const priceMatch = productPriceText.replace(/[^\d.,]/g, '').replace(',', '');
    productPriceNumber = parseFloat(priceMatch);
    expect(productPriceNumber).not.toBeNaN();
  });

  // Optionally, log the results for debugging
  // console.log({ productTitle, productPriceText, productPriceNumber });
});
